toml_template:
[[instances]]
jmx_url = "{{.jmx_url}}"
{{- if .username}}
username = "{{.username}}"
password = "{{.password}}"
{{- end}}

collect_jvm_heap = {{.collect_jvm_heap}}
collect_jvm_gc = {{.collect_jvm_gc}}
collect_jvm_threads = {{.collect_jvm_threads}}

labels = { instance="{{.jmx_url}}" }
interval = "{{.interval}}"
